def solve(words: Array[String]): Array[Long] = {
  val n = words.length
  val answer = Array.ofDim[Long](n)

  // Precompute the longest common prefix lengths between words[i] and words[j]
  val prefixLengths = Array.ofDim[Int](n)

  for (i <- 0 until n) {
    for (j <- 0 until i) {
      var lcp = 0
      while (lcp < words(i).length && lcp < words(j).length && words(i)(lcp) == words(j)(lcp)) {
        lcp += 1
      }
      prefixLengths(i) = lcp
    }
  }

  for (i <- 0 until n) {
    var maxLcp = 0L
    // Check with previous word
    if (i > 0) {
      maxLcp = Math.max(maxLcp, prefixLengths(i - 1))
    }
    // Check with next word
    if (i < n - 1) {
      maxLcp = Math.max(maxLcp, prefixLengths(i))
    }
    answer(i) = maxLcp
  }

  answer
}
